import React, { Component } from 'react';
import styled from 'styled-components';
import { Card, CardBody, CardTitle, CardSubtitle, CardText, CardImg, Row, Col } from 'reactstrap';

const Banner = styled.div`
    position: relative;
    padding: 0em;
`;

const ProfileContainer = styled.div`
    text-align: center;
`
const ProfileImage = styled.img`
    border-radius:50%;
    margin-top:20vh;
`
const ProfileBackground = styled.img`
    position:absolute;
    top:0;
    height: 100vh;
`

export class ProfileBanner extends Component {
    static displayName = ProfileBanner.name;

    constructor(props) {
        super(props);

        this.state = {
            priorScrollTop: null,
            initializedContent: <div/>
        }
    }


    render() {
        return (
            <Banner>
                <ProfileBackground src="profile_background.png"/>
                <ProfileContainer> 
                    <ProfileImage src='profile_image_round.png'/>
                    <h1>Bradley Mader</h1>
                    <h3>Software Engineer</h3>
                    <h3>Online/Backend</h3>
                </ProfileContainer>
            </Banner>
        );
    }
}
